import svg4everybody from 'svg4everybody';
import $ from 'jquery';

$(() => {
	svg4everybody();
	// Поставить инпуты (radio и checkbox) в положение checked, если у них атрибут data-check имеет значение true
	const inputs = document.querySelectorAll('[data-check="true"]');
	for (let i = 0; i < inputs.length; i++) {
		inputs[i].setAttribute('checked', 'checked');
	}
	// Слайдер
	const range = document.getElementById('holder');
	range.onmousedown = function (e) {
		function getCoords(el) {
			const box = el.getBoundingClientRect();
			return {
				left: box.left + pageXOffset
			};
		}
		const coords = getCoords(range);
		const shiftX = e.pageX - event.offsetX - coords.left;
		function moveAt(event) {
			range.style.left = event.clientX - event.offsetX - shiftX + 'px';
		}
		range.style.position = 'absolute';
		moveAt(e);
		document.onmousemove = function (elem) {
			moveAt(elem);
		};
		range.onmouseup = function () {
			document.onmousemove = null;
			range.onmouseup = null;
		};
	};
	range.ondragstart = function () {
		return false;
	};
});



